# Always evict in user+assistant PAIRS — never orphan a message
# An orphan assistant message at the start breaks message alternation
# and causes anthropic.BadRequestError: messages must alternate roles

def validate_message_structure(messages: list[dict]) -> bool:
    if not messages:
        return True
    if messages[0]['role'] != 'user':
        return False
    for i, m in enumerate(messages):
        expected = 'user' if i % 2 == 0 else 'assistant'
        if m['role'] != expected:
            return False
    return True

def safe_evict(
    messages: list[dict],
    max_tokens: int,
) -> list[dict]:
    # Evict oldest pairs until under budget or only 1 pair remains
    while len(messages) > 2 and count_message_tokens(messages) > max_tokens:
        messages = messages[2:]

    # Validate before returning — should always pass with pair eviction
    if not validate_message_structure(messages):
        raise ValueError(
            f'Message structure broken after eviction: '
            f'first role = {messages[0]["role"] if messages else "empty"}'
        )
    return messages

# Edge case: tool_use / tool_result pairs
# A tool_use block in an assistant message pairs with a tool_result in the next user message.
# If you evict the assistant turn containing tool_use but keep the following user
# message with tool_result, you create an invalid orphan.
# Solution: evict tool_use + tool_result together as a 4-message unit.

# Full ContextWindow class with anchoring, pair eviction, and usage tracking
import tiktoken
from dataclasses import dataclass, field

enc = tiktoken.get_encoding('cl100k_base')

@dataclass
class ContextWindow:
    max_history_tokens: int = 40_000
    anchor_pairs: int       = 1        # opening turns to always keep
    _messages: list[dict]   = field(default_factory=list)
    _summary: str           = ''
    _eviction_count: int    = 0

    def _count(self, messages: list[dict]) -> int:
        total = 0
        for m in messages:
            c = m.get('content', '')
            text = c if isinstance(c, str) else str(c)
            total += len(enc.encode(text)) + 4
        return total

    def add(self, role: str, content: str) -> None:
        self._messages.append({'role': role, 'content': content})
        self._enforce_budget()

    def _enforce_budget(self) -> None:
        anchor = self._messages[:self.anchor_pairs * 2]
        body   = self._messages[self.anchor_pairs * 2:]
        anchor_tokens = self._count(anchor)
        body_budget = self.max_history_tokens - anchor_tokens

        while len(body) > 2 and self._count(body) > body_budget:
            body = body[2:]  # drop oldest pair
            self._eviction_count += 1

        self._messages = anchor + body

    def messages(self) -> list[dict]:
        return list(self._messages)

    @property
    def token_count(self) -> int:
        return self._count(self._messages)

    @property
    def evictions(self) -> int:
        return self._eviction_count

# Usage
window = ContextWindow(max_history_tokens=40_000, anchor_pairs=1)
window.add('user', 'You are helping me plan a product launch.')
window.add('assistant', 'Understood. What is the product?')
window.add('user', 'A mobile app for expense tracking.')
# ... many turns later ...
print(f'Tokens in window: {window.token_count}')
print(f'Turns evicted: {window.evictions}')

# Handle tool_use / tool_result pairs correctly during eviction
# A tool_use block in an assistant message MUST be followed by a
# matching tool_result in the next user message — they form a 4-message unit.

def has_tool_use(message: dict) -> bool:
    content = message.get('content', '')
    if isinstance(content, list):
        return any(b.get('type') == 'tool_use' for b in content)
    return False

def has_tool_result(message: dict) -> bool:
    content = message.get('content', '')
    if isinstance(content, list):
        return any(b.get('type') == 'tool_result' for b in content)
    return False

def safe_evict_with_tools(
    messages: list[dict],
    max_tokens: int,
) -> list[dict]:
    while len(messages) > 4 and count_message_tokens(messages) > max_tokens:
        # Check if the oldest pair involves tool_use / tool_result
        if has_tool_use(messages[1]) and has_tool_result(messages[2]):
            # Tool pair spans 4 messages: user, assistant(tool_use),
            # user(tool_result), assistant(reply) — evict all 4
            messages = messages[4:]
        else:
            messages = messages[2:]  # standard pair eviction

        # Re-anchor: first message must be user role
        while messages and messages[0]['role'] != 'user':
            messages = messages[1:]

    return messages

# Progressive summarization: update the rolling summary incrementally
# rather than re-summarizing from scratch on every eviction
import anthropic

client = anthropic.Anthropic()

class SummaryWindow:
    def __init__(self, max_history_tokens: int = 30_000, keep_recent_pairs: int = 4):
        self.max_history_tokens = max_history_tokens
        self.keep_recent_pairs  = keep_recent_pairs
        self._messages: list[dict] = []
        self._summary: str = ''

    def add(self, role: str, content: str) -> None:
        self._messages.append({'role': role, 'content': content})
        if count_message_tokens(self._messages) > self.max_history_tokens:
            self._evict_and_summarize()

    def _evict_and_summarize(self) -> None:
        keep  = self._messages[-self.keep_recent_pairs * 2:]
        evict = self._messages[:-self.keep_recent_pairs * 2]

        if not evict:
            return

        # Build incremental summary prompt
        conversation_text = '\n'.join(
            f"{m['role'].upper()}: {m.get('content', '')[:400]}"
            for m in evict if isinstance(m.get('content'), str)
        )
        prior = f'Prior summary: {self._summary}\n\n' if self._summary else ''
        response = client.messages.create(
            model='claude-haiku-4-5-20251001',
            max_tokens=300,
            messages=[{'role': 'user', 'content': (
                f'{prior}Update this conversation summary with the new turns below. '
                f'Keep the result under 200 words. Focus on decisions, facts, and open questions.\n\n'
                f'{conversation_text}'
            )}],
        )
        self._summary = response.content[0].text
        self._messages = keep

    def messages_with_summary(self) -> list[dict]:
        if not self._summary:
            return self._messages
        return [
            {'role': 'user',      'content': f'[Summary of prior conversation]\n{self._summary}'},
            {'role': 'assistant', 'content': 'Understood.'},
        ] + self._messages
